macro_rules! hashmap {
    ($($key:expr => $val:expr),* $(,)?) => {
        {
            let mut map = std::collections::HashMap::new();
            $( map.insert($key, $val); )*
            map
        }
    };
}
let m = hashmap! {
    "one" => 1,
    "two" => 2,
};

macro_rules! impl_display {
    ($($t:ty),*) => {
        $(
            impl std::fmt::Display for $t {
                fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
                    write!(f, "{:?}", self)
                }
            }
        )*
    };
}
impl_display!(MyType, OtherType, ThirdType);

macro_rules! builder {
    ($name:ident { $($field:ident: $t:ty),* $(,)? }) => {
        struct $name { $($field: $t),* }
        impl $name {
            fn builder() -> paste::paste!{[<$name Builder>]} {
                paste::paste!{[<$name Builder>]::default()}
            }
        }
    };
}

